function getUserAndMarkSeen(userId: string): User | null {
  const user = userRepo.findById(userId);
  if (!user) return null;
  user.lastSeen = new Date();
  userRepo.save(user);
  return user;
}

class Counter {
  private count = 0;

  increment(): number {
    this.count += 1;
    return this.count;
  }
}

/* Version A */
class OrderServiceA {
  applyDiscount(orderId: string, percent: number): Order {
    const order = repo.find(orderId);
    order.total = order.total * (1 - percent / 100);
    repo.save(order);
    return order;
  }
}

